// This code analyzes the manuscript to determine the next chapter number
// Get the manuscript text
let manuscriptText = "";
try {
  if ($input && $input.last() && $input.last().json && $input.last().json.content) {
    manuscriptText = $input.last().json.content;
    console.log("Got manuscript, length:", manuscriptText.length);
  } else {
    console.log("Manuscript content not found in input");
  }
} catch (error) {
  console.log("Error accessing manuscript:", error.message);
}

// Find all chapters in the manuscript using the BEGIN/END markers
const chapterNumbers = [];
try {
  // Look for chapter markers in standard format
  const chapterPattern = /\[BEGIN CHAPTER (\d+)\]/g;
  let match;

  while ((match = chapterPattern.exec(manuscriptText)) !== null) {
    const chapterNum = parseInt(match[1], 10);
    chapterNumbers.push(chapterNum);
    console.log(`Found chapter ${chapterNum}`);
  }

  // Also look for MOP chapter format if present
  const mopPattern = /\[BEGIN MOP CHAPTER (\d+)\]/g;
  while ((match = mopPattern.exec(manuscriptText)) !== null) {
    const chapterNum = parseInt(match[1], 10);
    if (!chapterNumbers.includes(chapterNum)) {
      chapterNumbers.push(chapterNum);
      console.log(`Found MOP chapter ${chapterNum}`);
    }
  }
} catch (error) {
  console.log("Error finding chapters:", error.message);
}

// Get total chapters from form submission
let totalChapters = 0;
try {
  totalChapters = parseInt($('On form submission').first().json['Total Chapters'], 10);
} catch (error) {
  // Default if we can't get from form
  totalChapters = 30;
  console.log("Using default total chapters:", totalChapters);
}

// Find the highest chapter number in the manuscript
const highestChapter = chapterNumbers.length > 0 ? Math.max(...chapterNumbers) : 0;
console.log(`Highest chapter found in manuscript: ${highestChapter}`);

// The next chapter is simply the highest chapter + 1
const nextChapterNumber = highestChapter + 1;
console.log(`Next chapter to process: ${nextChapterNumber}`);

// Calculate progress
const completedCount = chapterNumbers.length;
const isComplete = nextChapterNumber > totalChapters;
const progressPercent = Math.round((completedCount / totalChapters) * 100);

// Get the target chapter name
const targetChapterName = `Chapter ${nextChapterNumber} Draft`;

// Extract the last 4 chapters for context
const recentChapters = chapterNumbers.slice(Math.max(0, chapterNumbers.length - 4));
console.log(`Recent chapters (last ${recentChapters.length}): ${recentChapters.map(ch => ch.number).join(', ')}`);

// Return the results
return {
  json: {
    nextChapterNumber: nextChapterNumber,
    targetChapterName: targetChapterName,
    isComplete: isComplete,
    totalChapters: totalChapters,
    completedCount: chapterNumbers.length,
    progressPercent: progressPercent,
    isFirstChapter: highestChapter === 0,
    lastChapterContent: recentChapters.length > 0 ? recentChapters[recentChapters.length - 1].content : "",    
    // Include found chapters for debugging
    foundChapters: chapterNumbers.sort((a, b) => a - b)
  }
};

// Get values from the Determine Next Chapter node's output
let nextChapterNumber, totalChapters;

try {
  // Get the original next chapter number from the Determine Next Chapter node
  const determineNode = $('Determine Next Chapter');
  if (determineNode && determineNode.item && determineNode.item.json) {
    // This is the chapter number we just processed
    const currentChapterNumber = determineNode.item.json.nextChapterNumber;
    totalChapters = determineNode.item.json.totalChapters;

    // Set nextChapterNumber to the next chapter (current + 1)
    nextChapterNumber = currentChapterNumber + 1;

    console.log(`Current chapter processed: ${currentChapterNumber}`);
    console.log(`Next chapter will be: ${nextChapterNumber}`);
  } else {
    console.log("Could not access Determine Next Chapter node data");
    // Default values if we can't access the node
    nextChapterNumber = 2; // Assume we just processed chapter 1
    totalChapters = 11;    // Default to 11 chapters
  }
} catch (error) {
  console.log("Error accessing Determine Next Chapter data:", error.message);
  // Default values if there's an error
  nextChapterNumber = 2;
  totalChapters = 11;
}

// Alternative approach: try to get the chapter number from the Draft MOP Chapter content
try {
  const draftNode = $('Draft MOP Chapter');
  if (draftNode && draftNode.item && draftNode.item.json && draftNode.item.json.text) {
    const draftText = draftNode.item.json.text;

    // Try to extract chapter number from BEGIN CHAPTER tag
    const chapterMatch = draftText.match(/\[BEGIN CHAPTER (\d+)\]/i);
    if (chapterMatch && chapterMatch[1]) {
      const chapterFromDraft = parseInt(chapterMatch[1]);
      console.log(`Found chapter number ${chapterFromDraft} in Draft MOP Chapter content`);

      // Use this as a cross-check
      if (chapterFromDraft + 1 !== nextChapterNumber) {
        console.log(`WARNING: Chapter number mismatch - Draft says ${chapterFromDraft}, Determine Next Chapter implies next is ${nextChapterNumber}`);
        // Trust the draft content over the determine node
        nextChapterNumber = chapterFromDraft + 1;
      }
    }
  }
} catch (error) {
  console.log("Error checking Draft MOP Chapter content:", error.message);
}

// Calculate completion status and progress
const isComplete = nextChapterNumber > totalChapters;
const progressPercent = Math.round(((nextChapterNumber - 1) / totalChapters) * 100);

console.log(`Next chapter will be: ${nextChapterNumber}`);
console.log(`Total chapters: ${totalChapters}`);
console.log(`Is complete: ${isComplete}`);
console.log(`Progress: ${progressPercent}%`);

// Return results
return {
  json: {
    nextChapterNumber,
    isComplete,
    totalChapters,
    progressPercent
  }
};

// Get manuscript content from input
let manuscriptContent = "";
try {
    manuscriptContent = $('Get MOP Manuscript').last().json.content || "";
    console.log(`Retrieved manuscript (${manuscriptContent.length} characters)`);
} catch (error) {
  console.log(`Error getting manuscript: ${error.message}`);
}

// Get data from the Determine Next Chapter node
const determineNode = $('Determine Next Chapter');
let nextChapterNumber = 6; // Default fallback
let isFirstChapter = false;
let foundChapters = [];

try {
  if (determineNode && determineNode.last() && determineNode.last().json) {
    // Extract chapter number information
    nextChapterNumber = determineNode.last().json.nextChapterNumber || 6;
    isFirstChapter = determineNode.last().json.isFirstChapter || false;
    foundChapters = determineNode.last().json.foundChapters || [];

    console.log(`Next chapter from Determine Next Chapter: ${nextChapterNumber}`);
    console.log(`Found ${foundChapters.length} chapters in manuscript`);
  } else {
    console.log("Could not access Determine Next Chapter node data");
  }
} catch (error) {
  console.log("Error accessing Determine Next Chapter data:", error.message);
}

// Determine which previous chapters to include (most recent 4 chapters)
const chaptersToInclude = 4;
const currentChapter = nextChapterNumber - 1;
const startChapter = Math.max(1, currentChapter - chaptersToInclude + 1);
const endChapter = currentChapter;

console.log(`Including chapters ${startChapter} through ${endChapter}`);

// Explicitly extract each chapter by searching for BEGIN/END markers
const recentChaptersContent = [];
const recentChapters = [];

for (let chNum = startChapter; chNum <= endChapter; chNum++) {
  console.log(`Looking for Chapter ${chNum}`);

  const beginMarker = `[BEGIN CHAPTER ${chNum}]`;
  const endMarker = `[END CHAPTER ${chNum}]`;

  const beginIndex = manuscriptContent.indexOf(beginMarker);

  if (beginIndex >= 0) {
    const endIndex = manuscriptContent.indexOf(endMarker, beginIndex);

    if (endIndex >= 0) {
      // Found both markers - extract the complete chapter
      const chapterContent = manuscriptContent.substring(beginIndex, endIndex + endMarker.length);
      console.log(`Found Chapter ${chNum} with BEGIN/END markers (${chapterContent.length} chars)`);
      recentChaptersContent.push(chapterContent);
      recentChapters.push({
        number: chNum,
        content: chapterContent
      });
    } else {
      // Only found begin marker - look for next chapter's begin
      console.log(`No END marker for Chapter ${chNum}, looking for next chapter start`);
      let nextBeginIndex = manuscriptContent.length;

      for (let nextChap = chNum + 1; nextChap <= endChapter + 2; nextChap++) {
        const nextBeginMarker = `[BEGIN CHAPTER ${nextChap}]`;
        const tempIndex = manuscriptContent.indexOf(nextBeginMarker);

        if (tempIndex > beginIndex && tempIndex < nextBeginIndex) {
          nextBeginIndex = tempIndex;
          console.log(`Found next chapter ${nextChap} start at ${nextBeginIndex}`);
          break;
        }
      }

      if (nextBeginIndex < manuscriptContent.length) {
        const chapterContent = manuscriptContent.substring(beginIndex, nextBeginIndex);
        console.log(`Found incomplete Chapter ${chNum} using next chapter marker (${chapterContent.length} chars)`);
        const completedContent = chapterContent + `[END CHAPTER ${chNum}]`;
        recentChaptersContent.push(completedContent);
        recentChapters.push({
          number: chNum,
          content: completedContent
        });
      }
    }
  } else {
    console.log(`Could not find BEGIN marker for Chapter ${chNum}`);
  }
}

console.log(`Found ${recentChapters.length} chapters to include`);

// Get the last chapter content
let lastChapterContent = "";
if (recentChapters.length > 0) {
  lastChapterContent = recentChapters[recentChapters.length - 1].content;
  console.log(`Last chapter content length: ${lastChapterContent.length} chars`);
}

// Format recent chapters as context string
let recentChaptersText = "### Recent Chapters for Context:\n\n";

if (recentChapters.length > 0) {
  recentChapters.forEach(chapter => {
    recentChaptersText += `Chapter ${chapter.number}:\n${chapter.content}\n\n`;
  });
  console.log(`Generated recent chapters text: ${recentChaptersText.length} chars`);
} else {
  recentChaptersText += "No recent chapters available\n\n";
  console.log("No chapters available for context");
}

// Create the dynamic context - make sure it has the same format as recentChaptersText
const dynamicContext = recentChaptersText;

// Get extracted chapter content from input if available
let extractedChapterContent = "";
try {
  if ($input && $input.first() && $input.first().json) {
    extractedChapterContent = $input.first().json.chapterContent || "";
  }
} catch (error) {
  console.log(`Error getting extracted chapter content: ${error.message}`);
}

// Return everything with more detailed information for debugging
return {
  json: {
    nextChapterNumber,
    isFirstChapter,
    recentChaptersText,
    dynamicContext,
    lastChapterContent,
    extractedChapterContent,
    recentChaptersCount: recentChapters.length,
    totalChaptersFound: foundChapters.length,
    debug: {
      manuscriptLength: manuscriptContent ? manuscriptContent.length : 0,
      determineNodeData: {
        available: !!determineNode?.last()?.json,
        nextChapter: determineNode?.last()?.json?.nextChapterNumber
      }
    }
  }
};

const docMap = {};
for (const item of items) {
  docMap[item.json.name] = item.json.id;
}
return [{ json: { docMap } }];

// Function to extract a single chapter from the original manuscript
function extractSingleChapter(items) {
  try {
    console.log("Starting chapter extraction from original manuscript");

    // Check input from Determine Next Chapter node
    if (!items[0].json || !items[0].json.nextChapterNumber) {
      console.log("Input data check:", JSON.stringify(items[0].json));
      return [{
        json: {
          error: "Missing input data. Expecting nextChapterNumber from Determine Next Chapter node.",
          chapterContent: ""
        }
      }];
    }

    // Get the target chapter number from the previous node
    const targetChapter = parseInt(items[0].json.nextChapterNumber, 10);
    console.log(`Target chapter to extract: ${targetChapter}`);

    // Get the original manuscript content from Get Manuscript node
    let originalManuscript = "";
    try {
      // Get the original manuscript (NOT the MOP manuscript)
      originalManuscript = $('Get Manuscript').last().json.content || "";
      console.log(`Original manuscript content length: ${originalManuscript.length}`);

      // Log a preview of the manuscript for debugging
      const preview = originalManuscript.substring(0, 300);
      console.log(`Original manuscript preview: ${preview}`);
    } catch (nodeError) {
      console.log("Error getting original manuscript:", nodeError.message);
      return [{
        json: {
          error: "Could not get content from 'Get Manuscript' node. Check connection.",
          chapterContent: ""
        }
      }];
    }

    // Find the chapter in the original manuscript using markers
    const beginMarker = `[BEGIN CHAPTER ${targetChapter}]`;
    const endMarker = `[END CHAPTER ${targetChapter}]`;

    const beginIndex = originalManuscript.indexOf(beginMarker);
    if (beginIndex === -1) {
      return [{
        json: {
          error: `Chapter ${targetChapter} not found in original manuscript. Missing marker: ${beginMarker}`,
          chapterContent: ""
        }
      }];
    }

    const endIndex = originalManuscript.indexOf(endMarker);
    if (endIndex === -1) {
      return [{
        json: {
          error: `End marker for Chapter ${targetChapter} not found in manuscript. Missing marker: ${endMarker}`,
          chapterContent: ""
        }
      }];
    }

    // Extract the content between markers (exclude the markers themselves)
    const startPos = beginIndex + beginMarker.length;
    const chapterContent = originalManuscript.substring(startPos, endIndex).trim();

    console.log(`Extracted ${chapterContent.length} characters for Chapter ${targetChapter}`);

    // Get chapter title from target name if available
    const chapterTitle = items[0].json.targetChapterName || `Chapter ${targetChapter}`;

    // Return the extracted chapter content and metadata
    return [{
      json: {
        chapterNumber: targetChapter,
        chapterTitle: chapterTitle,
        chapterContent: chapterContent,
        // Pass through any other important data from input
        totalChapters: items[0].json.totalChapters || 0,
        completedCount: items[0].json.completedCount || 0,
        progressPercent: items[0].json.progressPercent || 0,
        // Include any other metadata needed by downstream nodes
        isFirstChapter: items[0].json.isFirstChapter || false
      }
    }];

  } catch (error) {
    console.log("Error:", error.message);
    return [{
      json: {
        error: error.message,
        chapterContent: ""
      }
    }];
  }
}

// Execute the function
return extractSingleChapter($input.all());

const docMap = {};
for (const item of items) {
  docMap[item.json.name] = item.json.id;
}
return [{ json: { docMap } }];
